('ONET-CUSTOMS_BROKERS', 'source_onet_customs_brokers', 'Customs Brokers', 'Customs Brokers is an imported ONET role/occupation concept. It needs TALLENTIN normalization before production routing.', 'role_title', 'Prepare customs documentation and ensure that shipments meet all applicable laws to facilitate the import and export of goods. Determine and track duties and taxes payable and process payments on behalf of client. Sign documents under a power of attorney. Represent clients in meetings with customs officials and apply for duty refunds and tariff reclassifications. Coordinate transportation and storage of imported goods.', ARRAY['Air Export Agent','Air Export Operations Agent','Air Import Agent','Boarding Agent','Cargo Agent','Cargo Broker','Cargo Office Agent','Corporate Licensed Broker','Customs Agent','Customs Analyst','Customs and Border Patrol Agent (CBP Agent)','Customs Broker','Customs Brokerage Agent','Customs Brokerage Coordinator','Customs Brokerage Entry Writer','Customs Brokerage Representative','Customs Brokerage Specialist','Customs Compliance Analyst','Customs Compliance Specialist','Customs Consultant','Customs Coordinator','Customs Entry Specialist','Customs Entry Writer','Customs House Broker','Customs Specialist','Entry Writer','Export Administrator','Export Agent','Export Coordinator','Export Operations Agent','Exporter','Foreign Trade Manager','Import Agent','Import Coordinator','Import Specialist','Import-Export Agent','Import/Export Administrator','Import/Export Agent','Import/Export Specialist','Importer','Importer Exporter','International Trade Specialist','Licensed Customs Broker','Ocean Export Agent','Ocean Import Agent','Ocean Import Representative','Ocean Import Specialist','Operations Assistant','Trade Facilitator']::text[], ARRAY['Customs Brokers','Air Export Agent','Air Export Operations Agent','Air Import Agent','Boarding Agent','Cargo Agent','Cargo Broker','Cargo Office Agent','Corporate Licensed Broker','Customs Agent','Cus